import React, { useEffect, useState } from "react";
import { getFreelancerDashboard } from "../../api/api";
import { useNavigate } from "react-router-dom";

const FreelancerDashboard = () => {
  const navigate = useNavigate();

  const [data, setData] = useState({
    activeProjects: 0,
    pendingProposals: 0,
    projects: []
  });

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await getFreelancerDashboard();
        setData(res.data);
      } catch (err) {
        console.error("Dashboard Error:", err.response?.data || err.message);
        setError("Failed to load dashboard.");
      } finally {
        setLoading(false);
      }
    };
    fetchDashboard();
  }, []);

  if (loading) return (
    <div className="flex justify-center items-center h-64">
      <p className="text-gray-500 text-lg">Loading dashboard...</p>
    </div>
  );

  if (error) return (
    <div className="p-6 bg-red-100 text-red-600 rounded-lg">{error}</div>
  );

  return (
    <div className="max-w-7xl mx-auto">

      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-800">Welcome back 👋</h1>
        <p className="text-gray-500 mt-2">Here's your freelancing overview</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
        <div className="bg-white p-6 rounded-2xl shadow-sm border">
          <h4 className="text-gray-500 text-sm">Applied Projects</h4>
          <h2 className="text-3xl font-bold mt-2 text-blue-600">{data.activeProjects}</h2>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border">
          <h4 className="text-gray-500 text-sm">Pending Proposals</h4>
          <h2 className="text-3xl font-bold mt-2 text-yellow-500">{data.pendingProposals}</h2>
        </div>

        <div
          className="bg-teal-600 p-6 rounded-2xl shadow-sm cursor-pointer hover:bg-teal-700 transition"
          onClick={() => navigate("/freelancer/find-projects")}
        >
          <h4 className="text-teal-100 text-sm">Find New Projects</h4>
          <h2 className="text-xl font-bold mt-2 text-white">Browse Projects →</h2>
        </div>
      </div>

      {/* Projects Applied To */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border">
        <h2 className="text-xl font-semibold mb-5">Projects You Applied To</h2>

        {data.projects.length === 0 ? (
          <div className="text-center py-10">
            <p className="text-gray-500 text-lg mb-4">No applications yet. Start applying!</p>
            <button
              onClick={() => navigate("/freelancer/find-projects")}
              className="bg-teal-600 text-white px-6 py-2 rounded-lg hover:bg-teal-700 transition"
            >
              Find Projects
            </button>
          </div>
        ) : (
          <div className="space-y-4">
            {data.projects.map((project) => (
              <div key={project.proposal_id} className="border rounded-xl p-5 hover:shadow-sm transition">
                <div className="flex justify-between items-start">
                  <div className="flex-1">
                    <h3 className="text-lg font-semibold text-gray-800">{project.title}</h3>
                    <p className="text-gray-500 mt-1 text-sm">{project.description}</p>
                    <div className="flex gap-6 mt-3 text-sm">
                      <span className="text-gray-600">Budget: <strong>₹{project.budget}</strong></span>
                      <span className="text-teal-600">Your Bid: <strong>₹{project.bid}</strong></span>
                    </div>
                  </div>
                  <span className={`ml-4 px-3 py-1 rounded-full text-xs font-semibold capitalize whitespace-nowrap ${
                    project.proposal_status === "accepted"
                      ? "bg-green-100 text-green-600"
                      : project.proposal_status === "rejected"
                      ? "bg-red-100 text-red-600"
                      : "bg-yellow-100 text-yellow-600"
                  }`}>
                    {project.proposal_status || "pending"}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default FreelancerDashboard;
